  project_id: 'gen-lang-client-0591001769'
};

// Crear JWT para obtener access token
function base64url(str) {
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

function base64urlFromBuffer(buf) {
  let binary = '';
  const bytes = new Uint8Array(buf);
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

const now = Math.floor(Date.now() / 1000);
const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const payload = base64url(JSON.stringify({
  iss: SA.client_email,
  scope: 'https://www.googleapis.com/auth/cloud-platform',
  aud: 'https://oauth2.googleapis.com/token',
  exp: now + 3600,
  iat: now
}));

const signingInput = `${header}.${payload}`;

// Importar la clave privada y firmar
const pemKey = SA.private_key
  .replace('-----BEGIN PRIVATE KEY-----', '')
  .replace('-----END PRIVATE KEY-----', '')
  .replace(/\n/g, '')
  .trim();

const binaryKey = Uint8Array.from(atob(pemKey), c => c.charCodeAt(0));

const cryptoKey = await crypto.subtle.importKey(
  'pkcs8',
  binaryKey.buffer,
  { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
  false,
  ['sign']
);

const encoder = new TextEncoder();
const signature = await crypto.subtle.sign(
  'RSASSA-PKCS1-v1_5',
  cryptoKey,
  encoder.encode(signingInput)
);

const jwt = `${signingInput}.${base64urlFromBuffer(signature)}`;

// Obtener access token
const tokenRes = await $http.request({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`
});

const accessToken = tokenRes.access_token;
if (!accessToken) throw new Error('No se pudo obtener access token: ' + JSON.stringify(tokenRes));

// Llamar a Vertex AI Embeddings
const textToEmbed = `${item.title}\n\n${item.content}`.slice(0, 2000);

const vertexRes = await $http.request({
  method: 'POST',
  url: `https://us-central1-aiplatform.googleapis.com/v1/projects/${SA.project_id}/locations/us-central1/publishers/google/models/text-embedding-004:predict`,
  headers: {
    'Authorization': `Bearer ${accessToken}`,
    'Content-Type': 'application/json'
  },
  body: {
    instances: [{
      task_type: 'RETRIEVAL_DOCUMENT',
      content: textToEmbed
    }]
  }
});

const embedding = vertexRes.predictions?.[0]?.embeddings?.values;
if (!embedding || !Array.isArray(embedding)) {
  throw new Error(`Embedding inválido para "${item.id}": ${JSON.stringify(vertexRes).slice(0, 300)}`);
}

console.log(`✓ Embedding para "${item.id}": ${embedding.length} dims`);

return {
  json: {
    id: item.id,
    category: item.category,
    title: item.title,
    content: item.content,
    is_active: item.is_active,
    embedding: JSON.stringify(embedding)
  }
};

// El embedding ya viene incluido del nodo anterior
// Solo pasamos el item completo
return $input.item;

const allItems = $input.first().json.data || [];
const synced = allItems.length;

const summary = {
  ok: true,
  synced,
  timestamp: new Date().toISOString(),
  items: allItems.map(i => ({ id: i.id, title: i.title }))
};

console.log(`✅ Sync completado: ${synced} items`);
return [{ json: summary }];

const body = $input.first().json.body;

if (!body || !Array.isArray(body.items)) {
  throw new Error('Body inválido. Esperado: { items: [{id, category, title, content, is_active}] }');
}

const valid = body.items.filter(item => {
  if (!item.id || !item.category || !item.title || !item.content) {
    console.log(`Saltando item inválido: ${JSON.stringify(item).slice(0, 100)}`);
    return false;
  }
  return true;
});

console.log(`Items válidos: ${valid.length}/${body.items.length}`);
return valid.map(item => ({ json: item }));
